// ====================================
// PROCESAR RESPUESTAS DE BOTONES (TIPO BUTTON)
// ====================================
const entries = $input.all();
const buttonResponses = [];

for (const entry of entries) {
  const body = entry.json.body;

  if (body?.entry?.[0]?.changes?.[0]?.value?.messages) {
    const messages = body.entry[0].changes[0].value.messages;

    for (const message of messages) {
      // Filtrar solo respuestas de botones (type: button)
      if (message.type === 'button') {

        const phone = message.from;
        const messageId = message.id;
        const timestamp = message.timestamp;

        // Extraer datos del botón
        const buttonPayload = message.button.payload;
        const buttonText = message.button.text;

        console.log('=== RESPUESTA DE BOTÓN ===');
        console.log('Teléfono:', phone);
        console.log('Button Payload:', buttonPayload);
        console.log('Button Text:', buttonText);

        const phoneFormatted = phone.replace(/[^0-9]/g, '');

        let mensajeRespuesta = '';
        let shouldRespond = false;
        let saveToTable = false;

        // Comparar por payload O por texto
        if (buttonPayload === 'Me_interesa' || 
            buttonPayload === 'me_interesa' || 
            buttonText === 'Me interesa') {
          shouldRespond = true;
          saveToTable = true;

          const mensajeAsesor = "Hola, me interesa solicitar un crédito. ¿Pueden darme más información?";

          mensajeRespuesta = 
            "🎉 *¡Perfecto!*\n\n" +
            "💡 Un asesor está listo para atenderte AHORA MISMO.\n\n" +
            "📲 *TOCA AQUÍ* para hablar directamente con un asesor:\n" +
            "https://wa.me/595974270790?text=" + encodeURIComponent(mensajeAsesor) + "\n\n" +
            "⚡ Obtené tu crédito en minutos\n" +
            "💰 Sin papeleos complicados\n" +
            "✅ Aprobación inmediata\n\n" +
            "💼 *Créditos El Paisa*\n" +
            "Tu mejor opción en créditos rápidos y confiables.";
        } 
        else if (buttonPayload === 'No_me_interesa' || 
                 buttonPayload === 'no_me_interesa' || 
                 buttonText === 'No me interesa') {
          shouldRespond = true;
          saveToTable = false;

          mensajeRespuesta = 
            "Entendemos. 😊\n\n" +
            "Si en algún momento necesitás un crédito rápido para tu negocio, aquí estaremos para ayudarte.\n\n" +
            "¡Que tengas un excelente día! 👋\n\n" +
            "💰 *Créditos El Paisa*";
        }

        if (shouldRespond) {
          // CALCULAR TIMESTAMPS EN MILISEGUNDOS (ZONA HORARIA COLOMBIA)
          const now = new Date();

          // Colombia es UTC-5
          const colombiaOffsetMs = -5 * 60 * 60 * 1000;
          const currentTimeColombia = now.getTime() + colombiaOffsetMs;
          const reminderTimeColombia = currentTimeColombia + (15 * 60 * 1000); // +15 minutos

          console.log('Timestamp actual (Colombia):', currentTimeColombia);
          console.log('Timestamp recordatorio (Colombia):', reminderTimeColombia);
          console.log('Fecha actual legible:', new Date(currentTimeColombia).toISOString());
          console.log('Fecha recordatorio legible:', new Date(reminderTimeColombia).toISOString());

          buttonResponses.push({
            json: {
              phone: phoneFormatted,
              button_id: buttonPayload,
              button_title: buttonText,
              message_id: messageId,
              response_date: String(currentTimeColombia),  // Guardar como STRING del número
              reminder_date: String(reminderTimeColombia), // Guardar como STRING del número
              reminder_sent: false,
              saveToTable: saveToTable,
              whatsapp_payload: {
                messaging_product: "whatsapp",
                to: phoneFormatted,
                type: "text",
                text: {
                  body: mensajeRespuesta
                }
              }
            }
          });
        }
      }
    }
  }
}

console.log(`Total de respuestas procesadas: ${buttonResponses.length}`);
return buttonResponses;

// ====================================
// FILTRAR RECORDATORIOS PENDIENTES Y PREPARAR MENSAJES
// ====================================
const allRows = $input.all();

// Calcular timestamp actual en Colombia
const now = new Date();
const colombiaOffsetMs = -5 * 60 * 60 * 1000;
const nowColombiaMs = now.getTime() + colombiaOffsetMs;

const remindersToSend = [];

console.log(`Total de filas con reminder_sent=false: ${allRows.length}`);
console.log(`Timestamp actual (Colombia): ${nowColombiaMs}`);
console.log(`Fecha actual legible: ${new Date(nowColombiaMs).toISOString()}`);

for (const row of allRows) {
  const data = row.json;

  // Parsear reminder_date (guardado como string de timestamp)
  const reminderDateMs = parseInt(data.reminder_date);

  if (!isNaN(reminderDateMs)) {
    console.log(`Evaluando: ${data.phone}`);
    console.log(`  - Reminder timestamp: ${reminderDateMs}`);
    console.log(`  - Reminder legible: ${new Date(reminderDateMs).toISOString()}`);
    console.log(`  - Now timestamp: ${nowColombiaMs}`);

    // Verificar si ya pasó el tiempo
    if (reminderDateMs <= nowColombiaMs) {
      console.log(`✓ RECORDATORIO LISTO para ${data.phone}`);

      const mensajeRecordatorio = 
        "👋 *¡Hola de nuevo!*\n\n" +
        "Vimos que te interesó nuestro crédito. 😊\n\n" +
        "💡 *¿Todavía lo necesitás?*\n\n" +
        "Un asesor está disponible AHORA para ayudarte:\n\n" +
        "📲 *TOCA AQUÍ:*\n" +
        "https://wa.me/595974270790?text=" + encodeURIComponent("Hola, me interesa un credito, quiero mas informacion") + "\n\n" +
        "⚡ Respuesta inmediata\n" +
        "💰 Sin complicaciones\n" +
        "✅ Aprobación al instante\n\n" +
        "💼 *Créditos El Paisa*\n" +
        "Estamos para ayudarte cuando lo necesités.";

      remindersToSend.push({
        json: {
          id: data.id,
          phone: data.phone,
          whatsapp_payload: {
            messaging_product: "whatsapp",
            to: data.phone,
            type: "text",
            text: {
              body: mensajeRecordatorio
            }
          }
        }
      });
    } else {
      const minutosRestantes = Math.round((reminderDateMs - nowColombiaMs) / 60000);
      console.log(`✗ Aún no es hora para ${data.phone} - Faltan ${minutosRestantes} minutos`);
    }
  } else {
    console.log(`⚠️ No se pudo parsear la fecha para ${data.phone}: ${data.reminder_date}`);
  }
}

console.log(`Total de recordatorios a enviar: ${remindersToSend.length}`);
return remindersToSend;

// Limpiar y preparar el teléfono para el nodo de WhatsApp
const items = $input.all();

return items.map(item => {
  let telefono = item.json.Telefono || item.json["numero de telefono"];

  // Asegurarse que sea string y limpiar
  telefono = String(telefono).trim().replace(/[^0-9]/g, '');

  return {
    json: {
      ...item.json,
      telefono_limpio: telefono
    }
  };
});

